function solve(nums) {
    const n = nums.length;
    if (n <= 1) {
        return 0;
    }

    // D_prev stores D_{i-1}, the minimum required total increase applied to nums[i-1].
    let D_prev = 0;
    // total_cost accumulates the sum of all positive necessary increments (the minimum total cost).
    let total_cost = 0;

    // Iterate from the second element (i=1) onwards
    for (let i = 1; i < n; i++) {
        // We require nums[i] + D_curr >= nums[i-1] + D_prev
        // This implies D_curr >= D_prev + (nums[i-1] - nums[i])

        const required_D_value = D_prev + nums[i - 1] - nums[i];

        // Since D_curr must be non-negative, we take the maximum of 0 and the required value.
        const D_curr = Math.max(0, required_D_value);

        // The minimum cost incurred at this step is the necessary increase in the required total increase D, 
        // which is max(0, D_curr - D_prev).
        total_cost += Math.max(0, D_curr - D_prev);

        // Update D_prev for the next iteration
        D_prev = D_curr;
    }

    return total_cost;
}
