    if (n <= 1) {
        return 0;
    }

    // A_prev stores A[i-1], the minimum required value for the previous element.
    let aPrev = nums[0];

    // d_prev stores d[i-1] = A[i-1] - nums[i-1].
    // For i=1, we look at d[0] = A[0] - nums[0] = 0.
    let dPrev = 0; 

