    let cTotal = 0;

    // Iterate from the second element (i=1)
    for (let i = 1; i < n; i++) {
        // 1. Calculate A[i] = max(nums[i], A[i-1])
        // Since nums[i] and aPrev are within safe integer limits, standard comparison works.
        let aCurr = Math.max(nums[i], aPrev);

        // 2. Calculate d[i] = A[i] - nums[i]
        let dCurr = aCurr - nums[i];

        // 3. Calculate cost contribution: max(0, d[i] - d[i-1])
        // This represents the necessary jump in the required increase at this step.
        let costIncrease = Math.max(0, dCurr - dPrev);

        // 4. Update total cost
        cTotal += costIncrease;

        // 5. Prepare for the next iteration
        aPrev = aCurr;
        dPrev = dCurr;
