function solve(nums) {
    const n = nums.length;
    if (n <= 1) {
        return 0;
    }

    // D_prev_safe represents D_{i-1}, the total increase applied to nums[i-1].
    // We conceptually set D_{-1} = 0.
    let D_prev_safe = 0; 

    // N_prime_prev_safe represents N'_{i-1}, the value of the minimally required non-decreasing array at i-1.
    let N_prime_prev_safe = nums[0]; 

    let total_cost = 0;

    for (let i = 0; i < n; i++) {
        const current_nums = nums[i];

        let N_prime_current;

        if (i === 0) {
            // N'_0 must be at least nums[0], so N'_0 = nums[0] for the minimal required sequence.
            N_prime_current = current_nums;
        } else {
            // N'_i must be at least nums[i] and at least N'_{i-1}
            N_prime_current = Math.max(current_nums, N_prime_prev_safe);
        }

        // D_i = N'_i - nums[i] is the total increase required at index i.
        let D_current = N_prime_current - current_nums;

        // The cost is the sum of all positive increases in the required total increase D_i.
        // This corresponds to starting an operation of magnitude D_i - D_{i-1} at index i if D_i > D_{i-1}.
        let cost_increment = Math.max(0, D_current - D_prev_safe);

        total_cost += cost_increment;

        // Update state for the next iteration
        D_prev_safe = D_current;
        N_prime_prev_safe = N_prime_current;
    }

    return total_cost;
}
